{
  "type": "object",
  "title": "Luma Business Event Class",
  "description": "Luma Business Event Class",
  "allOf": [
    {
      "$ref": "https://ns.adobe.com/xdm/data/time-series"
    }
  ]
}

{
    "meta:resourceType": "mixins",
    "title": "Luma Product Inventory Event Details Field Group",
    "type": "object",
    "description": "Luma Product Inventory Event Details Field Group",
    "properties": {
        "{{TENANT_ID}}": {
            "type": "object",
            "properties": {
                "inventoryEvent": {
                    "title":"Inventory Event",
                    "type": "object",
                    "properties": {
                        "sku": {
                            "title": "SKU",
                            "description": "Unique identifier of the product",
                            "type": "string",
                            "isRequired": true,
                            "meta:xdmType": "string"
                        },
                        "stockEventType": {
                            "title": "Stock Event Type",
                            "description": "Number of items left in stock",
                            "type": "string",
                            "enum": [
                                "restock",
                                "outOfStock"
                            ],
                            "meta:enum": {
                                "restock": "Restock",
                                "outOfStock": "Out of Stock"
                            },
                            "isRequired": true,
                            "meta:xdmType": "string"
                        }
                    },
                    "meta:xdmType": "object",
                    "required": [
                        "sku"
                    ]
                }
            }
        }
    },
    "meta:extensible": true,
    "meta:abstract": true,
    "meta:intendedToExtend": [
        "{{luma_business_event_class_id}}"
    ]
}

{
    "meta:resourceType": "schemas",
    "title": "Luma Product Inventory Event Schema",
    "type": "object",
    "description": "Luma Product Inventory Event Schema",
    "allOf": [
        {
            "$ref": "{{luma_business_event_class_id}}",
            "type": "object",
            "meta:xdmType": "object"
        },
        {
            "$ref": "{{luma_product_inventory_event_fieldgroup_id}}",
            "type": "object",
            "meta:xdmType": "object"
        }
    ],
    "meta:extensible": false,
    "meta:abstract": false,
    "meta:extends": [
        "https://ns.adobe.com/xdm/data/time-series",
        "{{luma_product_inventory_event_fieldgroup_id}}",
        "{{luma_business_event_class_id}}"
    ],
    "meta:xdmType": "object"
}

{
    "name": "Luma Product Inventory Event Dataset",
    "schemaRef": {
        "id": "{{luma_product_inventory_event_schema_id}}",
        "contentType": "application/vnd.adobe.xed-full-notext+json; version=1"
    },
    "fileDescription": {
        "persisted": true,
        "containerFormat": "parquet",
        "format": "parquet"
    },
    "enableErrorDiagnostics": true
}
